import WidgetKit
import SwiftUI
import AppIntents

struct SportIntent: AppIntent {
    static var title: LocalizedStringResource = "Sport"
    @Parameter(title: "Name") var name: String
}

struct SportWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: "SportWidget",
            intent: SportIntent.self,
            provider: .static
        ) { entry in
            Text(entry.name)
        }
    }
}

