import WidgetKit
import SwiftUI
import AppIntents

enum HeartRateZone: String, AppEnum {
    case rest, fatBurn, cardio, peak
    static var typeDisplayRepresentation = TypeDisplayRepresentation(name: "HeartRateZone")
    static var caseDisplayRepresentations: [HeartRateZone: DisplayRepresentation] = [
        .rest: DisplayRepresentation(name: "Rest"),
        .fatBurn: DisplayRepresentation(name: "Fat Burn"),
        .cardio: DisplayRepresentation(name: "Cardio"),
        .peak: DisplayRepresentation(name: "Peak")
    ]
}

struct HeartZoneIntent: AppIntent {
    static var title: LocalizedStringResource = "Heart Zone"
    @Parameter(title: "Zone") var zone: HeartRateZone
}

struct HeartZoneWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: "HeartZoneWidget",
            intent: HeartZoneIntent.self,
            provider: .static
        ) { entry in
            Text(entry.zone.rawValue.capitalized)
        }
    }
}

